features.snippet:
interface MyIface;
  logic req;
endinterface
virtual MyIface vif;

MyIface if_inst();
virtual MyIface vif;
initial vif = if_inst;

interface MyIface;
  task send();
  endtask
endinterface
virtual MyIface vif;
initial vif.send();

module mod (virtual MyIface vif);
  initial vif.req = 1'b0;
endmodule

class Driver;
  virtual MyIface vif;
  function new(virtual MyIface v);
    vif = v;
  endfunction
endclass

interface ClockedIface (input clk);
  clocking cb @(posedge clk);
    inout data;
  endclocking
endinterface
virtual ClockedIface vif;
initial vif.cb.data <= 8'h00;
